INSERT INTO `empresa_infos` VALUES (3,'Empresa CodeGO - LГ­der em desenvolvimento econГґmico.','/static/empresa1.jpg'),(4,'Empresa ABC - SoluГ§Гµes inovadoras.','/static/empresa2.jpg'),(295,'','/static/empresa295.jpg'),(392,NULL,'/static/imagens_empresas/empresa392.jpeg'),(395,'HГЎ mais de 45 anos, a VITAMEDIC iniciou sua trajetГіria rumo ao sonho de transformar essa pequena empresa Goiana em referГЄncia nacional na produГ§ГЈo e comercializaГ§ГЈo de medicamentos.\n\nBuscamos diariamente pela concretizaГ§ГЈo desse sonho, trilhando o caminho de crescimento e consolidaГ§ГЈo da nossa marca no mercado. Por isso, em abril de 2015 passamos a pertencer ao Grupo JosГ© Alves e firmamos um recomeГ§o rumo ao sucesso.','/static/empresa395.jpg'),(422,'Investindo sempre em aprimoramento tecnolГіgico e apostando na extraordinГЎria forГ§a de trabalho de sua equipe, o Teuto atravessa quase 8 dГ©cadas vencendo desafios e passando com sucesso por todas as dificuldades.\n\nAtualmente, a companhia possui mais de 540 produtos registrados entre medicamentos de referГЄncia, genГ©ricos, genГ©ricos de marca (similares equivalentes Г”Г‡Гґ EQГ”Г‡Г–s), MIPГ”Г‡Г–s (medicamentos isentos de prescriГ§ГЈo), linha de especialidades, que incluiu os biossimilares. AlГ©m disso, temos os suplementos alimentares, cosmГ©ticos e produtos para a saГєde. Nos prГіximos anos, estГЎ programado o lanГ§amento de mais de 250 novas apresentaГ§Гµes.','/static/empresa422.jpeg'),(469,'','/static/empresa469.png'),(506,'A Granol Г© uma grande empresa brasileira do agronegГіcio, atuante no processamento de grГЈos, produГ§ГЈo de Гіleo de soja, farelo, biodiesel, lecitina e glicerina, com unidades importantes no complexo industrial do DAIA em AnГЎpolis (GO) e outras no Brasil, focando em qualidade, sustentabilidade e geraГ§ГЈo de valor para o agronegГіcio nacional, sendo uma das lГ­deres no setor.','/static/empresa506.png'),(539,'HГЎ mais de 45 anos, a VITAMEDIC iniciou sua trajetГіria rumo ao sonho de transformar essa pequena empresa Goiana em referГЄncia nacional na produГ§ГЈo e comercializaГ§ГЈo de medicamentos.\n\nBuscamos diariamente pela concretizaГ§ГЈo desse sonho, trilhando o caminho de crescimento e consolidaГ§ГЈo da nossa marca no mercado. Por isso, em abril de 2015 passamos a pertencer ao Grupo JosГ© Alves e firmamos um recomeГ§o rumo ao sucesso.','/static/empresa539.jpg'),(548,'A Brainfarma IndГєstria QuГ­mica e FarmacГЄutica S.A. Г© uma das maiores fabricantes de medicamentos do Brasil. Conta hoje com um dos mais modernos centros de pesquisa e desenvolvimento de produtos farmacГЄuticos no paГ­s.\n\nEm AnГЎpolis, estГЎ localizada a fГЎbrica de medicamentos, uma das maiores da AmГ©rica Latina, com cerca de 120 mil metros quadrados de ГЎreas construГ­da, que abriga mais de 4600 colaboradores.\n\nEssa unidade tem capacidade para produzir mais de 830 itens distintos, nas mais variadas formas farmacГЄuticas: sГіlidos, lГ­quidos, semissГіlidos, efervescentes, injetГЎveis, aerossГіis, dentre outras.','/static/empresa548.jpg'),(654,NULL,'/static/imagens_empresas/empresa654.webp'),(661,'','/static/empresa661.jpeg'),(925,'sadasdaccccc','imagens_empresas/empresa925.jpg'),(926,'otima churrascaria','/static/imagens_empresas/empresa926.jpg');
